240	function loadDocument(id) {
241	    var mimeType = "";
242	    var myBase64string = "";
243	    var obj = getattachmentdata;
244	
245	    var jsonObj1 = "{\"registrationId\" : \"" + id + "\",\"objectType\" : \"course\",\"objectRef\":\"\"}"
246	    jQuery.ajax({
247	        url: "/SabaApiRest/learning/getAttachmentData",
248	        type: "POST",
249	        data: jsonObj1,
250	        dataType: "json",
251	        cache: false,
252	        contentType: 'application/json',
253	        success: function (msg) {
254	                console.log("get data success : " + msg);
255	                mimeType = msg.mimeType;
256	                myBase64string = msg.data;
257	
258	                console.log(" myBase64string : " + myBase64string);
259	                if (mimeType != "NA" && myBase64string != "No Attachment Data found") {
260	                    //For IE using atob convert base64 encoded data to byte array
261	                    if (window.navigator && window.navigator.msSaveOrOpenBlob) {
262	                        var byteCharacters = atob(myBase64string);
263	                        var byteNumbers = new Array(byteCharacters.length);
264	                        for (var i = 0; i < byteCharacters.length; i++) {
265	                            byteNumbers[i] = byteCharacters.charCodeAt(i);
266	                        }
267	                        var byteArray = new Uint8Array(byteNumbers);
268	                        var blob = new Blob([byteArray], {
269	                            type: mimeType
270	                        });
271	                        window.navigator.msSaveOrOpenBlob(blob, fileName + '.' + fileExtension);
272	                    } else {
273	                        // Directly use base 64 encoded data for rest browsers (not IE)
274	                        var base64EncodedPDF = myBase64string;
275	                        var pdfWindow = window.open("", '_blank');
276	                        pdfWindow.opener = null;
277	                        pdfWindow.document.write("<html><body style='text-align: center;padding: 10px 0'><a style='font-family: RobotoBold,Arial,Helvetica,sans-serif;font-weight: normal;font-size: 1.1em;color: #0076ce;text-align: center;padding: 10px 0;text-decoration: underline;' width='80%'  height='100%'  href='data: " + mimeType + " ;base64, " + encodeURI(myBase64string) + "' download=" + fileName + fileExtension + ">Click here to download</a><br><br><iframe width='80%' height='100%' src='data: " + mimeType + " ;base64, " + encodeURI(myBase64string) + "'></iframe></body></html>")
278	
