        data: jsonObj1,
        dataType: "json",
        cache: false,
        contentType: 'application/json',
        success: function (msg) {
            getattachmentdata = msg;
            parseCourseAttachments(msg);
        },
        error: function (errmsg) {
            console.log("Error! m:message says failure f: checkIfLLCovered");
        }
    });
}

function parseCourseAttachments(obj) {
    var atchflag = 0;
    try {
        if (obj.length > 0) {

            for (var count = 0; count < obj.length; count++) {
                if ((obj[count].fileExtension == ".PDF".toLowerCase()) || (obj[count].fileExtension == ".DOCX".toLowerCase())) {

                    if (atchflag > 0) {
                        $jq(".dds__course-attachments").append(' | ')
                    }

                    //$jq(".course-attachment").append('<a  id="' + obj[count].id + '" class="course-desc-attach"><i class="fas fa-paperclip fa-sm"></i></i>&nbsp;' + obj[count].attachementName + '</a>')
//
//                    let courseDescription = (obj[count].category.toLowerCase() == "course description") ? "Course Outline" : obj[count].attachementName;
                    $jq(".dds__course-attachments").append('<a id="' + obj[count].id + '" class="course-desc-attach" href="#"><span class="dds__icon dds__icons dds__icon--doc-lines"></span>&nbsp;' + obj[count].attachementName + '</a>');

                    fileName = obj[count].fileName;
                    fileExtension = obj[count].fileExtension;
                    $jq(".dds__course-attachments").removeClass("dds__d-none");
                    $jq(".dds__course-attachments-title").removeClass("dds__d-none");
                    atchflag++;
                }
            }
        }

        $jq(".course-desc-attach").on("click", function () {
            var id = $jq(this).attr("id");
            loadDocument(id);
        });
    } catch (e) {
        errormsg();
    }
}

function loadDocument(id) {
    var mimeType = "";
    var myBase64string = "";
    var obj = getattachmentdata;

    var jsonObj1 = "{\"registrationId\" : \"" + id + "\",\"objectType\" : \"course\",\"objectRef\":\"\"}"
    jQuery.ajax({
        url: "/SabaApiRest/learning/getAttachmentData",
        type: "POST",
        data: jsonObj1,
        dataType: "json",
        cache: false,
        contentType: 'application/json',
        success: function (msg) {
                console.log("get data success : " + msg);
                mimeType = msg.mimeType;
                myBase64string = msg.data;

                console.log(" myBase64string : " + myBase64string);
                if (mimeType != "NA" && myBase64string != "No Attachment Data found") {
                    //For IE using atob convert base64 encoded data to byte array
                    if (window.navigator && window.navigator.msSaveOrOpenBlob) {
                        var byteCharacters = atob(myBase64string);
                        var byteNumbers = new Array(byteCharacters.length);
                        for (var i = 0; i < byteCharacters.length; i++) {
                            byteNumbers[i] = byteCharacters.charCodeAt(i);
                        }
                        var byteArray = new Uint8Array(byteNumbers);
                        var blob = new Blob([byteArray], {
                            type: mimeType
                        });
                        window.navigator.msSaveOrOpenBlob(blob, fileName + '.' + fileExtension);
                    } else {
                        // Directly use base 64 encoded data for rest browsers (not IE)
                        var base64EncodedPDF = myBase64string;
                        var pdfWindow = window.open("", '_blank');
                        pdfWindow.opener = null;
                        pdfWindow.document.write("<html><body style='text-align: center;padding: 10px 0'><a style='font-family: RobotoBold,Arial,Helvetica,sans-serif;font-weight: normal;font-size: 1.1em;color: #0076ce;text-align: center;padding: 10px 0;text-decoration: underline;' width='80%'  height='100%'  href='data: " + mimeType + " ;base64, " + encodeURI(myBase64string) + "' download=" + fileName + fileExtension + ">Click here to download</a><br><br><iframe width='80%' height='100%' src='data: " + mimeType + " ;base64, " + encodeURI(myBase64string) + "'></iframe></body></html>")

                    }
                } else {
                    $jq("#addtocart .modal-body").text("No Attachment Found");
                    $jq(".addtocarterr").click();
                }
            }

            ,
        error: function (errmsg) {
            //console.log("error");
        }
    });
}

function bypassCartFree(){

    let classid = $jq(".dds__radio-button__input:checked").attr("data-classnum");
    let emailID = DOMPurify.sanitize($jq(".dt-emc-header").data("eid"));
    let authId = DOMPurify.sanitize($jq(".dt-emc-header").data("aid"));

    if (classid == null || classid == "") {
        classid = "";
    }
    localStorage.setItem('courseDetailsTitle',$jq(".dds__course-title").text());

    var jsonObj1 = {};

    let learnerId = DOMPurify.sanitize($jq(".dt-emc-header").data("empid"));

    jsonObj1 = {
        "username" : emailID.replace(/"/g, ""),
        "offeringNo" : classid,
        "sabaCert" : authId,
        "learnerId": learnerId
    };

    jQuery.ajax({
        url: "/SabaApiRest/mycertifications/registerOnOfferingNo",
        type: "POST",
        data: JSON.stringify(jsonObj1),
        dataType: "json",
        cache: false,
        contentType: 'application/json',
    }).done(function(msg) {
        console.log("**Register OFfering No response : " +  JSON.stringify(msg));
        LoadingIndicatorelementInit.hide();
        if(msg.registerStatus[0].statusCode == 300){
            triggerModal("Registration Notification", `<p>${msg.registerStatus[0].statusDescription} <br/></br/><button class="dds__button dds__button--block dds__button--secondary dds__button--md" type="button" onClick="closeModal()">Ok</button></p>`);
        } else {
            registrationID = msg.registerStatus[0].regId;
            window.open("/content/dell/"+ countryLocale +"/home/mytraining.html?regId="+registrationID+"&source=courseDetails", '_self');
        }
    }).fail(function() {
        LoadingIndicatorelementInit.hide();
        triggerModal("Error! Please contact admin", `<p><button class="dds__button dds__button--block dds__button--secondary dds__button--md" type="button" onClick="closeModal()">OK</button></p>`);
    });
}

function setShoppingCartCookies(offeringTitle, deliverMode, price, currency, offeringID, skuNumber, ptaType, curSymbol, trainingCredits, country) {

    var cookieObj = {
        'offeringTitle': offeringTitle,
        'deliverMode': deliverMode,
        'price': price,
        'currency': currency,
        'offeringId': offeringID,
        'skuNumber': skuNumber,
        'ptaType': ptaType,
        'quantity': '1',
        'curSymbol': curSymbol,
        'trainingCredits': trainingCredits,
        'country': country
    }

    //If country cookie value has changed then wipe the current cookies before adding the new one.
    if (dellShoppingCart.length > 0) {
        //console.log("Shopping Cart length = " + dellShoppingCart.length);
        var cookieCheck = JSON.parse(readCookie("shoppingCart_catlog"));
        if (cookieCheck[0].country != country) {
            console.log(cookieCheck[0].country + "!=" + country);
            dellShoppingCart = [];
        }
    }

    dellShoppingCart.push(cookieObj);
    console.log(dellShoppingCart);
    var json_str = JSON.stringify(dellShoppingCart);

    createCookie("shoppingCart_catlog",json_str,1);
    setCartcount();
}

function setCartcount() {
  		dellShoppingCart = JSON.parse(DOMPurify.sanitize(readCookie("shoppingCart_catlog")));
            $jq("#dds__cart-count .dds__badge__label").html(dellShoppingCart.length);
