                </div>
          `;
};

function embedTableDetails(data){
    if(data.length > 0){
        const virtualclassColumns = [{ value: "Location" , sortBy: "ascending", render: cellRadRenderer, maxWidth: 100 }, { value: "Language", fit: true, sortBy: "ascending"  }, { value: "Start Date", fit: true, sortBy: "ascending" }, { value: "End Date", fit: true, sortBy: "ascending" },{ value: "Session", minWidth: 100, maxWidth:120, sortBy: "ascending" },{ value: "Seats Available", fit: true, sortBy: "ascending" }, { value: "Price", render: priceCellRenderer, minWidth: 100, maxWidth:120, sortBy: "ascending" }];
        const classroomColumns = [{ value: "Location", sortBy: "ascending", render: cellRadRenderer, fit: true}, { value: "Facility", fit: true, sortBy: "ascending"}, { value: "Language", fit: true, sortBy: "ascending"  }, { value: "Start Date", fit: true, sortBy: "ascending" }, { value: "End Date", fit: true, sortBy: "ascending" },{ value: "Session", fit: true, sortBy: "ascending" },{ value: "Seats Available", fit: true, sortBy: "ascending" }, { value: "Price", render: priceCellRenderer, fit: true, sortBy: "ascending" }];
        const othermodColumns = [{ value: "Available Languages", render: cellRadRenderer, maxWidth:120, sortBy: "ascending" }];
        var columns;
                var modType = window.courseModType;

        if(modType == "Virtual Class"){
            columns = virtualclassColumns;
        } else if(modType == "Classroom"){
            columns = classroomColumns;
        } else {
            columns = othermodColumns;
        }
        const element = document.getElementById("dds__table_coursedetails");
                  DDS.Table(element, {
                    data,
                    columns,
                  });
        setTimeout(function(){
            if(data.length == 1){
                $jq(".dds__radio-button__input").prop("checked", true);
                $jq(".dds__button-CTA-CD-User").removeClass("disabled");
                $jq("#dds__table_coursedetails .dds__tbody .dds__tr").on("click", function(){
                    $jq(this).find('.dds__radio-button__label')[0].click();
                    $jq(".dds__button-CTA-CD-User").removeClass("disabled");
                })
            }
        }, 500);

        setTimeout(function(){
            $jq("#dds__table_coursedetails .dds__tbody .dds__tr").on("click", function(){
                $jq(this).find('.dds__radio-button__label')[0].click();
                $jq(".dds__button-CTA-CD-User").removeClass("disabled");
            })
        }, 500);
    }
}

