package com.dell.core.services;

import com.dell.core.bean.CourseInfoResponse;
import com.fasterxml.jackson.databind.ObjectMapper;
import org.apache.http.Consts;
import org.apache.http.HttpHeaders;
import org.apache.http.client.config.RequestConfig;
import org.apache.http.client.fluent.Executor;
import org.apache.http.client.fluent.Request;
import org.apache.http.client.fluent.Response;
import org.apache.http.entity.ContentType;
import org.apache.http.impl.client.CloseableHttpClient;
import org.apache.http.impl.client.HttpClients;
import org.json.JSONObject;
import org.osgi.service.component.annotations.Component;

import java.nio.charset.StandardCharsets;

@Component(service = CourseApiClient.class)
public class CourseApiClient {

    private static final ObjectMapper MAPPER = new ObjectMapper();

    public CourseInfoResponse getOfferingsAndCourseInfo(
            String absoluteUrl,
            JSONObject jsonPayload
    ) throws Exception {

        RequestConfig requestConfig = RequestConfig.custom()
                .setConnectTimeout(3000)
                .setSocketTimeout(6000)
                .setConnectionRequestTimeout(3000)
                .setRedirectsEnabled(false)
                .build();

        try (CloseableHttpClient httpClient = HttpClients.custom()
                .setDefaultRequestConfig(requestConfig)
                .disableRedirectHandling()
                .build()) {

            Executor executor = Executor.newInstance(httpClient);

            Response resp = executor.execute(
                    Request.Post(absoluteUrl)
                            .addHeader(HttpHeaders.ACCEPT, "application/json; charset=utf-8")
                            .addHeader(HttpHeaders.CONTENT_TYPE, "application/json; charset=utf-8")
                            .bodyString(jsonPayload.toString(),
                                    ContentType.APPLICATION_JSON.withCharset(Consts.UTF_8))
            );

            String body = resp.returnContent().asString(StandardCharsets.UTF_8);
            return MAPPER.readValue(body, CourseInfoResponse.class);
        }
    }

    public static String safeJsonForScriptTag(String json) {
        if (json == null) return "{}";
        // prevent "</script>" breaking the HTML
        return json.replace("</", "<\\/");
    }
}

